    let end_line = start_line + lines_in_match;
    let end_column = if lines_in_match > 0 {
        match_content.lines().last().map(|l| l.len()).unwrap_or(0) + 1
    } else {
        start_column + match_content.len()
    };

    Span::new(
        start_byte,
        end_byte,
        start_line,
        end_line,
        start_column,
        end_column,
    )
