        let score1 = keywords
            .iter()
            .map(|k| content1.matches(k).count())
            .sum::<usize>();
        let score2 = keywords
            .iter()
            .map(|k| content2.matches(k).count())
            .sum::<usize>();

        if score1 > 0 && score2 > 0 {
            let similarity = (score1.min(score2) as f64) / (score1.max(score2) as f64);
            if similarity > 0.5 {
                patterns.push(format!("semantic_{pattern_type}"));
            }
        }
    }

    patterns
}

